function solve(nums: number[], k: number): number {
    if (nums.length === 1) {
        return 0;
    }

    // Sort the array to easily find min and max in subarrays
    nums.sort((a, b) => a - b);

    // Use a sliding window approach to find the longest subarray that is balanced
    let left = 0;
    let maxLength = 1; // At least one element is always balanced

    for (let right = 1; right < nums.length; right++) {
        // Check if the current window [left, right] is balanced
        while (left <= right && nums[right] > nums[left] * k) {
            left++;
        }

        // Update the maximum length of balanced subarray
        maxLength = Math.max(maxLength, right - left + 1);
    }

    // The minimum number of elements to remove is total elements minus the maximum balanced subarray length
    return nums.length - maxLength;
}

